    <title>Valorant 战绩分析 - 无畏契约数据中心</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        :root {
            --primary-bg: #0a0e27;
            --secondary-bg: #0f1419;
            --tertiary-bg: #1a1e33;
            --accent-red: #ff4655;
            --accent-red-light: #ff6b7a;
            --text-primary: #f4f4f4;
            --text-secondary: #b8bcc4;
            --gold: #e8d66b;
            --border-color: #2a2e42;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Helvetica Neue', sans-serif;
            background-color: var(--primary-bg);
            color: var(--text-primary);
            line-height: 1.6;
        }

        /* 导航栏 */
        .navbar {
            background-color: var(--secondary-bg);
            border-bottom: 2px solid var(--accent-red);
            padding: 0 20px;
            position: sticky;
            top: 0;
            z-index: 100;
            box-shadow: 0 4px 20px rgba(255, 70, 85, 0.1);
        }

        .navbar-container {
            display: flex;
            justify-content: space-between;
            align-items: center;
            max-width: 1600px;
            margin: 0 auto;
            height: 70px;
        }

        .navbar-logo {
            font-size: 24px;
            font-weight: bold;
            color: var(--accent-red);
            text-transform: uppercase;
            letter-spacing: 2px;
            text-shadow: 0 0 20px rgba(255, 70, 85, 0.5);
        }

        .navbar-menu {
            display: flex;
            gap: 30px;
            list-style: none;
        }

        .navbar-menu a {
            color: var(--text-secondary);
            text-decoration: none;
            font-weight: 500;
            transition: all 0.3s ease;
            position: relative;
        }

        .navbar-menu a:hover {
            color: var(--accent-red);
        }

        .navbar-menu a::after {
            content: '';
            position: absolute;
            bottom: -5px;
            left: 0;
            width: 0;
            height: 2px;
            background-color: var(--accent-red);
            transition: width 0.3s ease;
        }

        .navbar-menu a:hover::after {
            width: 100%;
        }

        /* 主容器 */
        .container {
            display: flex;
            max-width: 1600px;
            margin: 20px auto;
            gap: 20px;
            padding: 0 20px;
        }

        /* 左侧边栏 */
        .sidebar {
            width: 280px;
            flex-shrink: 0;
        }

        .sidebar-card {
            background-color: var(--secondary-bg);
            border: 1px solid var(--border-color);
            border-left: 4px solid var(--accent-red);
            border-radius: 8px;
            padding: 20px;
            margin-bottom: 20px;
            transition: all 0.3s ease;
        }

        .sidebar-card:hover {
            background-color: var(--tertiary-bg);
            box-shadow: 0 8px 24px rgba(255, 70, 85, 0.15);
            transform: translateX(5px);
        }

        .sidebar-title {
            font-size: 14px;
            font-weight: bold;
            color: var(--accent-red);
            text-transform: uppercase;
            letter-spacing: 1px;
            margin-bottom: 15px;
        }

